const positions = $input.first().json;
if (!Array.isArray(positions) || positions.length === 0) {
  return [{ json: { actions: [], alerts: [] } }];
}

const actions = [];
const alerts = [];

for (const pos of positions) {
  // Fetch current market price from Polymarket
  let currentPrice = pos.current_price || pos.entry_price || 0;
  try {
    const resp = await fetch('https://gamma-api.polymarket.com/markets/' + pos.market_id);
    if (resp.ok) {
      const market = await resp.json();
      const prices = typeof market.outcomePrices === 'string' ? JSON.parse(market.outcomePrices) : market.outcomePrices;
      if (pos.direction === 'YES' && prices?.[0]) currentPrice = parseFloat(prices[0]);
      else if (pos.direction === 'NO' && prices?.[1]) currentPrice = parseFloat(prices[1]);
    }
  } catch {}

  const entryPrice = pos.entry_price || 0;

  // Take profit: price > 0.85
  if (currentPrice > 0.85) {
    actions.push({ id: pos.id, action: 'exit', reason: 'take_profit', currentPrice, entryPrice, market_id: pos.market_id });
  }
  // Stop loss: price < 0.08 and entered at > 0.20
  else if (currentPrice < 0.08 && entryPrice > 0.20) {
    actions.push({ id: pos.id, action: 'exit', reason: 'stop_loss', currentPrice, entryPrice, market_id: pos.market_id });
  }
  // Position weakening alert
  else if (currentPrice < 0.30 && entryPrice > 0.50) {
    alerts.push({ id: pos.id, question: pos.question || pos.market_id, currentPrice, entryPrice });
  }

  // Update current price in DB
  actions.push({ id: pos.id, action: 'update_price', currentPrice });
}

return [{ json: { actions, alerts, positionCount: positions.length } }];

const data = $input.first().json;

// Update prices in Supabase
for (const a of data.actions.filter(a => a.action === 'update_price')) {
  await fetch('https://fdabygmromuqtysitodp.supabase.co/rest/v1/trading_positions?id=eq.' + a.id, {
    method: 'PATCH',
    headers: {
      'apikey': $env.SUPABASE_ANON_KEY,
      'Authorization': 'Bearer ' + $env.SUPABASE_ANON_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ current_price: a.currentPrice })
  });
}

// Close positions that need exit
for (const a of data.actions.filter(a => a.action === 'exit')) {
  await fetch('https://fdabygmromuqtysitodp.supabase.co/rest/v1/trading_positions?id=eq.' + a.id, {
    method: 'PATCH',
    headers: {
      'apikey': $env.SUPABASE_ANON_KEY,
      'Authorization': 'Bearer ' + $env.SUPABASE_ANON_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ status: 'closed', close_reason: a.reason, current_price: a.currentPrice })
  });
}

return [{ json: { ...data, updated: true } }];

